-- ====================================================
-- 1. 테이블 생성
-- ====================================================

-- 문제 테이블 (공개 - 정답/해설 없음)
CREATE TABLE IF NOT EXISTS questions (
  id            SERIAL PRIMARY KEY,
  q_num         INTEGER NOT NULL,
  question_text TEXT    NOT NULL,
  choices       JSONB   NOT NULL  -- ["보기1","보기2","보기3","보기4"]
);

-- 정답 테이블 (비공개 - anon 직접 접근 불가)
CREATE TABLE IF NOT EXISTS answers (
  id             SERIAL  PRIMARY KEY,
  question_id    INTEGER REFERENCES questions(id) ON DELETE CASCADE,
  correct_option INTEGER NOT NULL,   -- 1~4
  explanation    TEXT    NOT NULL,
  detail         JSONB   DEFAULT '[]'
);

-- RLS 활성화
ALTER TABLE questions ENABLE ROW LEVEL SECURITY;
ALTER TABLE answers   ENABLE ROW LEVEL SECURITY;

-- questions: 누구나 읽기 가능
CREATE POLICY "public_read_questions" ON questions
  FOR SELECT USING (true);

-- answers: 정책 없음 = anon/authenticated 직접 SELECT 불가
--          (Edge Function의 service_role 만 접근 가능)


-- ====================================================
-- 2. 문제 데이터 삽입 (정답 없음)
-- ====================================================

ON CONFLICT (id) DO NOTHING;

-- ====================================================
-- 3. 정답·해설 데이터 삽입 (비공개)
-- ====================================================

ON CONFLICT DO NOTHING;

-- ====================================================
-- 4. 시퀀스 리셋 (삽입 후 AUTO INCREMENT 동기화)
-- ====================================================
SELECT setval('questions_id_seq', 200);
SELECT setval('answers_id_seq',   200);
