INSERT INTO questions (id, q_num, question_text, choices) VALUES
  (1, 1, '1. 대만특색차 국제 자격증 과정 취득 자격 요건은 무엇인가?', '["중화민국(대만) 국적이 아닌 외국인이어야 합니다.", "차업개량장이 승인한 기관에서 개설한 과정을 이수하고, 이론 및 실기 성적이 70점 이상이어야 합니다.", "차업개량장이 지정한 대만 내 두 곳의 차 산지를 방문하고, 온라인으로 방문 소감을 작성하며 사진을 업로드해야 합니다.", "모두 해당됨"]'),
  (2, 2, '2. 대만차가 국제 시장에 처음 수출된 시기는 언제인가?', '["1796년", "1869년", "1911년", "1945년"]'),
  (3, 3, '3. 청나라 말기, 대만차의 주요 수출 시장은 어느 나라였는가?', '["영국", "미국", "일본", "독일"]'),
  (4, 4, '4. 동방미인이 처음 만들어지기 시작한 시기는 언제인가?', '["청말시기", "일치시기", "대만 광복 초기", "21세기"]'),
  (5, 5, '5. 대만 차나무 재배와 생산의 본격적인 발전은 어느 지역에서 차 품종을 도입하면서 시작되었는가?', '["미국 뉴욕", "일본 시즈오카", "영국 런던", "중국 복건성"]'),
  (6, 6, '6. 대만의 야생 차나무에 대해 최초로 언급한 문헌은 지금으로부터 약 몇 년 전에 쓰여졌는가?', '["50여 년 전", "100여 년 전", "200여 년 전", "300여 년 전"]'),
  (7, 7, '7. 대만에서 가장 이른 시기에 제다에 활용된 것으로 알려진 차나무로 옳은 것은 무엇인가?', '["대만 원생 산차", "청심대유", "경지홍심", "청심오룡"]'),
  (8, 8, '8. 청나라 시대에 대만에서 원생 산차(山茶)가 발견된 곳은 어디인가?', '["아리산", "영강산", "수사련", "삼림계"]'),
  (9, 9, '9. 대만 차를 최초로 수출한 사람은 누구인가?', '["가조", "존 도드", "장내묘", "임봉지"]'),
  (10, 10, '10. 대만 최초의 차 연구 기관은 어느 시기에 설립되었는가?', '["청나라 시기", "네덜란드 통치기", "일치시기", "중화민국 시대"]'),
  (11, 11, '11. 대만차의 생산·유통 변천은 어떤 차종에서 가장 먼저 시작되었는가?', '["녹차", "포종차", "우롱차", "홍차"]'),
  (12, 12, '12. 현재 행정구역으로 나눈 4대 차 지역 중 재배 면적이 가장 넓은 차 지역은 다음 중 어디인가?', '["북부차구", "중부차구", "남부차구", "동부차구"]'),
  (13, 13, '13. 현재 대만 차 연간 생산량은 어느 정도인가?', '["1.2~1.6만 톤", "2.2~2.6만 톤", "3.2~3.6만 톤", "4.2~4.6만 톤"]'),
  (14, 14, '14. 대만의 차 재배 면적은 대략 어느 정도인가?', '["9천 헥타르", "1.2만 헥타르", "2.2만 헥타르", "3.2만 헥타르"]'),
  (15, 15, '15. 현재 대만에서 차나무 재배 면적이 가장 넓은 지역은 어디인가?', '["신죽현", "대중시", "남투현", "가의현"]'),
  (16, 16, '16. 다음 중 철관음 차의 주요 생산지는 어디인가?', '["목책", "평림", "삼협", "용담"]'),
  (17, 17, '17. 대만 항구차는 어디에서 생산되는가?', '["명간향", "녹곡향", "녹야향", "만주향"]'),
  (18, 18, '18. 대만 벽라춘 녹차의 주요 생산지는 어디인가?', '["평림", "목책", "용담", "삼협"]'),
  (19, 19, '19. 대만에서 고산 오룡차 생산 면적이 가장 넓은 지역은 어디인가?', '["신북시", "대중시", "남투현", "가의현"]'),
  (20, 20, '20. 대만 동부의 대표적인 차 생산 지역은 어디인가?', '["삼협", "녹야", "명간", "가의"]'),
  (21, 21, '21. 차의 일반적인 분류 방식으로 옳은 것은 무엇인가?', '["발효(산화) 정도", "계절", "품종", "모두 해당됨"]'),
  (22, 22, '22. 다음 중 대엽종 차나무의 분류학적 명칭으로 옳은 것은 무엇인가?', '["Camellia sinensis var. sinensis", "Camellia sinensis var. arabica", "Camellia sinensis var. assamica", "Camellia formosensis"]'),
  (23, 23, '23. 다음 중 소엽종 차나무의 분류학적 명칭으로 옳은 것은 무엇인가?', '["Camellia sinensis var. sinensis", "Camellia sinensis var. arabica", "Camellia sinensis var. assamica", "Camellia formosensis"]'),
  (24, 24, '24. 대엽종 차나무의 일반적인 생장 형태로 옳은 것은 무엇인가?', '["일년생 관목", "일년생 소교목", "다년생 관목", "다년생 소교목"]'),
  (25, 25, '25. 다음 중 대만에서 흔히 볼 수 있는 차나무 품종 분류에 해당하지 않는 것은 무엇인가?', '["거엽종", "대엽종", "소엽종", "원생 산차"]'),
  (26, 26, '26. 대차 12호 품종의 상품명은 무엇인가?', '["금훤(金萱)", "취옥(翠玉)", "홍옥(紅玉)", "홍운(紅韻)"]'),
  (27, 27, '27. 청심오룡을 잎의 크기로 분류하면 다음 중 어디에 속하는가?', '["세엽종", "소엽종", "중엽종", "대엽종"]'),
  (28, 28, '28. 다음 중 소엽종에 속하는 차나무 품종은 무엇인가?', '["청심오룡", "대만산차", "대차 18호", "대차 8호"]'),
  (29, 29, '29. 다음 중 차나무 품종 분류에 관한 설명으로 옳지 않은 것은 무엇인가?', '["차나무는 크게 대엽종과 소엽종으로 분류된다", "하나의 차나무 품종은 단일 차 종류만 생산할 수 있다", "소엽종은 녹차 또는 부분 발효(산화) 차 종류 제조에 적합하다", "소엽종으로도 홍차를 제조할 수 있다"]'),
  (30, 30, '30. 대차 18호 품종의 상품명은 무엇인가?', '["금훤(金萱)", "취옥(翠玉)", "홍옥(紅玉)", "홍운(紅韻)"]'),
  (31, 31, '31. 대차 18호를 잎의 크기로 분류하면 다음 중 어디에 속하는가?', '["세엽종", "소엽종", "중엽종", "대엽종"]'),
  (32, 32, '32. 다음 중 대엽종 홍차 제조에 가장 적합한 차나무 품종은 무엇인가?', '["청심감자", "대차 18호", "대차 12호", "사계춘"]'),
  (33, 33, '33. 현재 대만에서 주로 생산되는 차 종류는 무엇인가?', '["녹차", "부분발효차", "홍차", "흑차"]'),
  (34, 34, '34. 현재 대만 전역에서 재배 면적이 가장 넓은 차나무 품종은 무엇인가?', '["청심대유", "청심오룡", "대차 12호", "대차 18호"]'),
  (35, 35, '35. 중저지대 다원에서 5~6월 사이에 채엽하여 제조하는 차는 어떤 계절의 차로 구분하는가?', '["봄차", "여름차", "가을차", "겨울차"]'),
  (36, 36, '36. 다음 중 발효(산화)시키지 않는 차는 무엇인가?', '["백차", "홍차", "녹차", "흑차"]'),
  (37, 37, '37. 다음 중 부분 발효(산화)차로 옳은 것은 무엇인가?', '["오룡차", "녹차", "홍차", "흑차"]'),
  (38, 38, '38. 다음 중 완전 발효(산화) 차로 옳은 것은 무엇인가?', '["흑차", "홍차", "녹차", "오룡차"]'),
  (39, 39, '39. 다음 중 현행 대만 특색차 분류에 해당하지 않는 것은 무엇인가?', '["청향형 조형 포종차", "청향형 구형 오룡차", "배향형 구형 포종차", "동방미인"]'),
  (40, 40, '40. 차 발효(산화)의 올바른 원리로 옳은 것은 무엇인가?', '["폴리페놀의 산화", "세균 작용", "효모 작용", "곰팡이 작용"]'),
  (41, 41, '41. 다음 중 대만 차 종류의 발효(산화) 정도 비교로 옳은 것은 무엇인가?', '["고산오룡차 > 홍차 > 삼협벽라춘", "고산오룡차 > 홍오룡 > 삼협벽라춘", "홍차 > 동정오룡 > 문산포종", "동방미인 > 고산오룡차 > 철관음"]'),
  (42, 42, '42. 대만에서 생산되는 차 종류 중 발효(산화)도가 가장 낮은 것은 무엇인가?', '["문산포종", "동정오룡", "철관음", "동방미인"]'),
  (43, 43, '43. 대만에서 생산되는 차 종류 중 발효(산화)도가 가장 높은 것은 무엇인가?', '["문산포종", "동정오룡", "철관음", "홍오룡"]'),
  (44, 44, '44. 다음 특색차 중 구형의 차는 무엇인가?', '["동정오룡", "고산오룡차", "철관음", "모두 해당됨"]'),
  (45, 45, '45. 다음 특색차 중 조형이 아닌 차는 무엇인가?', '["동정오룡", "고산오룡차", "철관음", "모두 해당되지 않음"]'),
  (46, 46, '46. 다음 특색차 중 조형의 차는 무엇인가?', '["동정오룡", "고산오룡차", "철관음", "문산포종"]'),
  (47, 47, '47. 다음 대만 특색차 중 발효(산화)도가 가장 높은 것은 무엇인가?', '["문산포종", "동정오룡", "동방미인", "고산오룡차"]'),
  (48, 48, '48. 다음 중 발효(산화) 과정을 거치지 않는 차 종류는 무엇인가?', '["녹차", "동정오룡", "문산포종", "동방미인"]'),
  (49, 49, '49. 다음 중 발효(산화) 정도가 가장 높은 차 종류는 무엇인가?', '["홍차", "오룡차", "녹차", "포종차"]'),
  (50, 50, '50. 구형 차 제다에 필수적인 공정은 무엇인가?', '["민황", "포유(단유)", "발효(산화)", "모두 해당됨"]'),
  (51, 51, '51. 다음 특색차 중 일광위조 공정을 거치지 않는 차는 무엇인가?', '["대엽종홍차", "고산오룡차", "철관음", "문산포종"]'),
  (52, 52, '52. 다음 대만 특색차 중 실내정치위조와 교반을 거치는 차는 무엇인가?', '["문산포종", "홍오룡", "철관음", "모두 해당됨"]'),
  (53, 53, '53. 다음 특색차 중 단유(포유) 공정을 거치는 차는 무엇인가?', '["문산포종", "홍오룡", "동방미인", "삼협벽라춘"]'),
  (54, 54, '54. 다음 특색차 중 배화 공정을 거치는 차는 무엇인가?', '["문산포종", "동방미인", "동정오룡", "소엽종홍차"]'),
  (55, 55, '55. 다음 중 대만 차에 대한 일반적인 설명으로 옳은 것은 무엇인가?', '["홍차는 완전 발효(산화) 차로, 구형을 띤다", "문산포종은 발효(산화) 정도가 가장 높은 부분 발효(산화) 차이다", "삼협벽라춘은 불발효(산화) 차로, 녹차에 속한다", "동정오룡은 배화 정도가 가장 강한 구형 차이다"]'),
  (56, 56, '56. 다음 특색차 중 일광위조 공정이 없는 차는 무엇인가?', '["문산포종", "동정오룡", "철관음", "대만홍차"]'),
  (57, 57, '57. 다음 중 포유(단유) 과정을 거치지 않는 차는 무엇인가?', '["동정오룡", "철관음", "동방미인", "홍오룡"]'),
  (58, 58, '58. 다음 중 일광위조와 실내 정치위조를 모두 거치는 차는 무엇인가?', '["문산포종", "삼협벽라춘", "백차", "대엽종홍차"]'),
  (59, 59, '59. 다음 중 일광위조가 필수적인 차는 무엇인가?', '["철관음", "대엽종홍차", "삼협벽라춘", "백차"]'),
  (60, 60, '60. 다음 중 일광위조와 실내정치위조를 모두 거치는 차는 무엇인가?', '["동정오룡", "소엽종 홍차", "삼협벽라춘", "삼협용정차"]'),
  (61, 61, '61. 다음 중 홍배 정도가 가장 높은 대만 특색차는 무엇인가?', '["문산포종", "동정오룡", "동방미인", "고산오룡차"]'),
  (62, 62, '62. 다음 중 차개장이 제시한 6대 다류 풍미룬에 해당하지 않는 것은 무엇인가?', '["청향형 조형 포종차", "배향형 조형 포종차", "청향형 구형 오룡차", "배향형 구형 오룡차"]'),
  (63, 63, '63. 차개장이 제시한 풍미룬을 6가지로 분류할 때, 분류 기준에 속하지 않는 것은 무엇인가?', '["차 종류", "제다 방식", "외형", "색상"]'),
  (64, 64, '64. 다음 중 배화형 구형 오룡차의 대표 차가 아닌 것은 무엇인가?', '["동정오룡", "철관음", "고산오룡차", "홍오룡"]'),
  (65, 65, '65. 다음 중 부분발효(산화)차에 속하는 것은 무엇인가?', '["홍차", "녹차", "오룡차", "벽라춘녹차"]'),
  (66, 66, '66. 대만홍차는 다음 중 어디에 속하는가?', '["불발효차", "부분발효차", "반발효차", "완전발효차"]'),
  (67, 67, '67. 다음 중 대만의 부분발효차에 해당하는 것은 무엇인가?', '["문산포종", "동정오룡", "동방미인", "모두 해당됨"]'),
  (68, 68, '68. 문산포종은 다음 중 어디에 속하는가?', '["부분발효차", "완전발효차", "불발효차", "후발효차"]'),
  (69, 69, '69. 다음 중 발효(산화)차에 속하지 않는 것은 무엇인가?', '["녹차", "포종차", "오룡차", "홍차"]'),
  (70, 70, '70. 벽라춘 녹차는 다음 중 어디에 속하는가?', '["불발효차", "부분발효차", "후발효차", "완전발효차"]'),
  (71, 71, '71. 6대 차류 풍미룬은 종류별로 전형적인 풍미 특성이 제각각 다릅니다. 그렇다면 이 풍미룬 구조에서 ''전형적 풍미 특성''은 대략 몇 시 방향에 위치합니까?', '["6시 방향", "4시 방향", "9시 방향", "1시 방향"]'),
  (72, 72, '72. 다음 중 풍미룬에서 차의 구감을 설명하는 항목이 아닌 것은 무엇인가?', '["여운", "농도", "순도", "균형"]'),
  (73, 73, '73. 풍미룬 사용에 관해 다음 중 옳은 것은 무엇인가?', '["동방미인 풍미룬의 풍미 묘사 어휘는 총 100종이므로, 하나의 동방미인 시료에서 이 백가지 향미를 모두 느낄 수 있다", "대만 특색차 풍미룬은 해당 차종에 존재할 수 있는 향미를 설명하며, 여기에는 긍정적 향미와 부정적 향미가 모두 포함된다", "풍미룬의 향기 분류에는 과향, 단향, 화향, 청향, 배향 및 기타 등 대분류가 있으므로, 하나의 차 시료를 평가할 때 각 분류의 향기를 반드시 평가해야 한다", "풍미룬은 차의 등급과 직접 연결되므로, 차 경연에서 입상한 차일수록 풍미 묘사가 더 많아진다"]'),
  (74, 74, '74. 풍미룬의 구감에 대한 설명 중 틀린 것은 무엇인가?', '["여운(餘韻感)의 정도는 짧은 것에서 긴 것까지 다양하며, 대만차가 중시하는 회감, 운미는 이 여운의 표현이다", "두께감(濃稠度)은 차를 마신 후 입안에 느껴지는 농도의 감각으로, 그 정도는 얇음(옅음)에서 두꺼움(걸쭉함)까지 다양하다", "밀도(細緻度)는 성근 것(거침)에서 촘촘한 것(매끄러움)까지 다양하며, 차탕에서 흔히 묘사되는 떫은맛은 이 항목에 포함된다", "순도(純淨度)란 입 안이 깨끗하고 맑은 느낌 또는 답답하고 잡한 느낌을 가리킨다"]'),
  (75, 75, '75. 다음 중 차업개량장이 제시한 특색차 풍미룬 1.0과 2.0의 차이점이 아닌 것은 무엇인가?', '["1.0은 203개 용어가 사용되었고, 2.0은 69개 용어가 사용되었다", "2.0은 6개의 풍미룬을 1개로 통합하였다", "2.0 의 향기 어휘는 대만 차에서 자주 접할 수 있는 54가지의 향기이다", "1.0은 소비자용, 2.0은 전문가용이다"]'),
  (76, 76, '76. 다음 중 대만차 분류 제도(TAGs)의 핵심 가치가 아닌 것은 무엇인가?', '["안전 보장", "자국 생산 보장", "가격 보호", "산업, 정부, 학계 및 전문가에 의한 분류 및 등급 지정"]'),
  (77, 77, '77. 다음 중 차업개량장이 제시한 대만 차 분류 등급 시스템(TAGs)의 차 등급에 해당하지 않는 것은 무엇인가?', '["특선", "정선", "우선", "수선"]'),
  (78, 78, '78. 「대만 차 풍미 플랫폼」(https://www.tags.org.tw)은 TAGs 평가의 전용 플랫폼이다. 다음 중 옳은 것은 무엇인가?', '["TAGs 평가 방법에 대한 소개가 있다", "플랫폼에는 평가를 거친 차의 포장, 평가 보고서, 차 농가 연락처 등 정보가 있어 향기롭고 맛있는 차를 편리하게 구입할 수 있다", "대만 차 국제 인증 과정 신청 페이지도 이 플랫폼에 있으며, 수강생은 신청 및 소감문 업로드, 전자 인증서 다운로드 등을 할 수 있다", "모두 해당됨"]'),
  (79, 79, '79. 신북시 삼협차구에서 녹차 생산에 주로 사용되는 차나무 품종은 무엇인가?', '["청심감자", "대차 12호", "대차 8호", "대만산차"]'),
  (80, 80, '80. 다음 중 대만에서 주로 생산되는 녹차는 무엇인가?', '["태평후괴", "삼협벽라춘", "말차", "옥로차"]'),
  (81, 81, '81. 다음 중 삼협벽라춘의 제다 공정 순서로 옳은 것은 무엇인가?', '["차청 - 실내정치위조 - 유념 - 건조", "차청 - 살청(초청) - 실내정치위조 - 유념 - 건조", "차청 - 실내정치위조 - 살청(초청) - 유념 - 건조", "차청 - 일광위조 - 살청(초청) - 유념 - 건조"]'),
  (82, 82, '82. 현행 삼협벽라춘 제다에서 추가된 첫 번째 공정은 무엇인가?', '["실내정치위조", "유념", "살청", "건조"]'),
  (83, 83, '83. 다음 중 대만 녹차의 전형적인 특징 풍미는 무엇인가?', '["과향", "청향", "배향", "화향"]'),
  (84, 84, '84. 벽라춘 녹차의 외관은 어떤 형태인가?', '["쇄형", "조형", "반구형", "구형"]'),
  (85, 85, '85. 벽라춘 녹차의 주요 향형은 무엇인가?', '["청향", "화향", "숙향", "밀향"]'),
  (86, 86, '86. 다음 중 고품질 고급 오룡차를 제조하기에 적합한 채엽 기준은 무엇인가?', '["1아1엽", "1아2엽", "1아 2~3엽, 그리고 대구 2~3엽", "대구 3~4엽"]'),
  (87, 87, '87. 다음 중 위조 공정의 주요 목적이 아닌 것은 무엇인가?', '["찻잎 내 수분 제거", "건조 속도 증가", "찻잎 내 화학 변화 촉진", "찻잎의 질감 연화 및 후속 가공 용이화"]'),
  (88, 88, '88. 다음 중 살청(초청)의 목적으로 옳은 것은 무엇인가?', '["찻잎 내 수분 함량 감소", "폴리페놀 산화효소의 비활성화", "풋내 제거", "모두 해당됨"]'),
  (89, 89, '89. 다음 중 유념의 목적으로 옳은 것은 무엇인가?', '["찻잎 내 수분 함량 감소", "폴리페놀 산화효소의 비활성화", "잎 내부의 세포 조직 파괴 및 즙액의 찻잎 표면 부착", "모두 해당됨"]'),
  (90, 90, '90. 다음 중 건조의 목적으로 옳은 것은 무엇인가?', '["찻잎 내 수분 함량 감소", "품질을 이상적인 상태로 고정", "찻잎 모양 고정", "모두 해당됨"]'),
  (91, 91, '91. 경위조, 경교반을 일반적으로 채택하며, 외관은 조형이고 향기는 청향을 지닌 차 종류는 무엇인가?', '["삼협벽라춘", "밀향홍차", "문산포종", "동방미인"]'),
  (92, 92, '92. 부분발효(산화)차의 제다에서, 실내정치위조 및 교반의 주요 목적으로 옳은 것은 무엇인가?', '["건조", "성형", "찻잎의 발효(산화) 억제", "찻잎의 발효(산화) 촉진으로 인한 향기 형성"]'),
  (93, 93, '93. 다음 중 경위조, 경교반, 경산화시키는 청향형 조형 포종차는 무엇인가?', '["삼협벽라춘", "문산포종", "고산오룡차", "동방미인"]'),
  (94, 94, '94. 다음 중 청향형 조형 포종차의 전형적인 특징 풍미는 무엇인가?', '["과향", "청향", "배향", "화향"]'),
  (95, 95, '95. 신북시에서 생산되는 문산포종의 주요 향형은 무엇인가?', '["화향", "숙과향", "배향", "밀향"]'),
  (96, 96, '96. 문산포종의 외관으로 옳은 것은 무엇인가?', '["쇄형", "조형", "반구형", "구형"]'),
  (97, 97, '97. 대만 고산차의 대표 산지에 포함되지 않는 것은 무엇인가?', '["아리산", "옥산", "육귀", "리산"]'),
  (98, 98, '98. 다음 중 반구형 고산 오룡차의 제다 공정 순서로 옳은 것은 무엇인가?', '["차청 - 일광위조 - 실내정치위조 및 교반 - 살청(초청) - 유념 - 초건 - 단유 - 건조", "차청 - 일광위조 - 실내정치위조 및 교반 - 살청(초청) - 유념 - 초건 - 건조", "살청(초청) - 일광 위조 - 실내정치위조 및 교반 - 살청(초청) - 단유 - 유념 - 초건 - 건조", "차청 - 일광위조 - 살청(초청) - 유념 - 단유 - 건조"]'),
  (99, 99, '99. 부분 발효(산화) 차의 제다 과정에서, 천으로 싸서 공 모양으로 만들고, 지속적으로 열을 가하는 공정을 반복해서 만드는 차의 종류는 무엇인가?', '["동정오룡", "문산포종", "밀향홍차", "동방미인"]'),
  (100, 100, '100. 다음 중 경위조하고, 경중(輕中)교반하며, 경발효 (산화)시킨 청향형 구형 오룡차의 종류는 무엇인가?', '["삼협벽라춘", "문산포종", "고산 오룡차", "동방미인"]'),
  (101, 101, '101. 다음 중 단유의 목적으로 옳은 것은 무엇인가?', '["무게 증가", "폴리페놀 산화효소의 비활성화", "조형의 찻잎을 구형으로 성형", "모두 해당됨"]'),
  (102, 102, '102. 다음 중 단유 공정에서 일반적으로 사용되지 않는 기계는 무엇인가?', '["곤륜유념기", "곤륜속포기", "연화속포기", "평유기"]'),
  (103, 103, '103. 제다 중 단유 과정에 관한 기본 작업 순서로서, 다음 중 옳은 것은 무엇인가?', '["평유 → 속포 → 복초 → 해괴", "복초 → 속포 → 평유 → 해괴", "속포 → 복초 → 해괴 → 평유", "평유 → 복초 → 속포 → 해괴"]'),
  (104, 104, '104. 고품질 고산 오룡차 제조에 적합한 채엽 기준은 무엇인가?', '["1아 1~2엽", "대구 1~2엽", "1아 2~3엽 및 대구 2~3엽", "대구 3~4엽"]'),
  (105, 105, '105. 다음 중 청향형 구형 오룡차의 전형적인 특징 풍미는 무엇인가?', '["과향", "청향", "배향", "화향"]'),
  (106, 106, '106. 고산 오룡차의 외관으로 알맞은 것은 무엇인가?', '["쇄형", "조형", "구형", "방형"]'),
  (107, 107, '107. 고산 오룡차의 주요 향미로 알맞은 것은 무엇인가?', '["채소, 과일향", "화향", "배향", "밀향"]'),
  (108, 108, '108. 도죽묘 차구에서 동방미인의 제다에 주로 사용되는 차나무 품종은 무엇인가?', '["청심감자", "대차 18호", "청심대유", "대엽오룡"]'),
  (109, 109, '109. 고품질 동방미인 제조에 적합한 찻엽 기준은 무엇인가?', '["1아", "1아 1~2엽", "1아 2~3엽", "1아 3~4엽"]'),
  (110, 110, '110. 다음 중 배화의 목적으로 옳은 것은 무엇인가?', '["찻잎에 특별한 배화향을 부여하기 위해서", "모차의 풋내와 불량한 이취를 개선하기 위해서", "수분을 제거하여 찻잎의 저장 기간을 연장하기 위해서", "모두 해당됨"]'),
  (111, 111, '111. 다음 중 대만 전통 특색차 종류의 배화 정도를 비교한 것으로 옳은 것은 무엇인가?', '["동정오룡 > 철관음", "철관음 > 동정오룡", "홍오룡 > 철관음", "동정오룡 = 철관음"]'),
  (112, 112, '112. 다음 중 동정오룡 제다 공정의 순서로 옳은 것은 무엇인가?', '["차청 - 일광위조 - 실내정치위조 및 교반 - 살청(초청) - 유념 - 초건 - 단유 - 건조", "차청 - 일광위조 - 실내정치위조 및 교반 - 살청(초청) - 유념 - 초건 - 단유 - 건조 - 배화", "차청 - 일광위조 - 실내정치위조 및 교반 - 살청(초청) - 단유 - 유념 - 초건 - 건조 - 배화", "차청 - 일광위조 - 살청(초청) - 유념 - 단유 - 건조 - 배화"]'),
